-- باب هرمي كامل جديد: "فقه الأسرة" (مسار fiqh، مرحلة التأسيس،
-- sort_order 9) — استكمال طبيعي بعد fiqh-muamalat، بنفس منهجية سلسلة
-- الأركان الخمسة. يغطي تكوين عقد الزواج وانحلاله والحضانة، بزاوية
-- مختلفة تماماً عن fiqh-women (التي غطت: الاستحاضة، الحجاب، عدة
-- المطلقة، عدة المتوفى عنها زوجها، المهر، النفقة الزوجية، الخلع).
--
-- تحقُّق تكرار مسبق شامل: "لا نكاح إلا بولي" موجود بالفعل في
-- bulugh-maram — تجنِّب ركن الولي هنا، التركيز على الإيجاب والقبول
-- والشهود. "النفقة" في fiqh-women عن نفقة الزوجة تحديداً (الطلاق:6-7 +
-- بخاري 5049) — هنا نفقة الأولاد بآية مختلفة كلياً (البقرة:233).
-- "الخلع"/"عدة المطلقة" في fiqh-women مغطاة — هنا الطلاق من زاوية عدده
-- وأنواعه (رجعي/بائن) لا آثاره على المرأة. صفر تكرار حرفي للاستشهادات:
-- تحقَّق أن مقطع "الطلاق مرتان" (مطلع البقرة:229) لم يُستشهَد به من قبل
-- (مقطع مختلف عن "فإن خفتم ألا يقيما حدود الله" المُستخدَم في خلع
-- fiqh-women من نفس الآية الطويلة).
DO $$
DECLARE
  v_course_id uuid;
  v_unit_id uuid;
BEGIN
  INSERT INTO courses (stage_id, slug, title, description, learning_goal, level, sort_order, pass_percentage, outcomes, status)
  VALUES (
    '9a50da27-e4bc-48a0-ba1f-bf68fa3f3e30',
    'fiqh-usra',
    'فقه الأسرة',
    'باب فقهي تأسيسي في أحكام تكوين الأسرة وانحلالها: أركان عقد النكاح، تعدد الزوجات وشروطه، المحرمات من النساء تأبيداً، أقسام الطلاق وأحكامه، والحضانة ونفقة الأولاد — كل حكم مُسنَد لآية قرآنية أو حديث صحيح موثَّق بنصه ورقمه.',
    'أن يعرف الطالب أركان عقد النكاح، وضوابط تعدد الزوجات، والمحرمات من النساء تأبيداً، وأقسام الطلاق (الرجعي والبائن)، وأحكام الحضانة ونفقة الأولاد.',
    'foundational',
    9,
    70,
    '["معرفة أركان عقد النكاح وشروطه", "معرفة ضوابط تعدد الزوجات", "معرفة المحرمات من النساء تأبيداً", "معرفة أقسام الطلاق الرجعي والبائن", "معرفة أحكام الحضانة ونفقة الأولاد"]'::jsonb,
    'published'
  )
  RETURNING id INTO v_course_id;

  INSERT INTO course_units (course_id, title, sort_order)
  VALUES (v_course_id, 'الدروس', 1)
  RETURNING id INTO v_unit_id;

  INSERT INTO learning_items (unit_id, item_type, title, description, session_estimate, weight, sort_order, status, is_approved)
  VALUES
  (v_unit_id, 'lesson', 'أركان عقد النكاح',
   'عقد النكاح عقد شرعي يُحلُّ به استمتاع الزوجين أحدهما بالآخر، وله أركان لا يصح العقد إلا باستيفائها: الزوجان (بأهليتهما الشرعية)، والصيغة (الإيجاب من ولي المرأة أو من يقوم مقامه، والقبول من الزوج)، والشهود. جاء التوجيه النبوي بإشهار النكاح وعدم كتمانه في حديث عائشة رضي الله عنها، عن النبي ﷺ: «أعلنوا هذا النكاح، واجعلوه في المساجد، واضربوا عليه بالدفوف» — رواه الترمذي، كتاب النكاح، وقال عنه: «حديث غريب حسن». الحكمة من الإعلان: تمييز النكاح الصحيح عن السفاح المستور، وتحقيق مقصد الزواج الاجتماعي في بناء أسرة معلنة لا علاقة سرية.',
   1.0, 14.29, 1, 'published', true),
  (v_unit_id, 'lesson', 'تعدد الزوجات وشروطه',
   'أباح الله تعالى للرجل الجمع بين أكثر من زوجة، بشرط العدل بينهن، وقيَّد ذلك بأربع كحد أقصى عند جمهور الفقهاء. قال الله تعالى: ﴿وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَىٰ فَانكِحُوا مَا طَابَ لَكُم مِّنَ النِّسَاءِ مَثْنَىٰ وَثُلَاثَ وَرُبَاعَ فَإِنْ خِفْتُمْ أَلَّا تَعْدِلُوا فَوَاحِدَةً أَوْ مَا مَلَكَتْ أَيْمَانُكُمْ ذَٰلِكَ أَدْنَىٰ أَلَّا تَعُولُوا﴾ (النساء: 3). ربطت الآية إباحة التعدد بشرط القدرة على العدل بين الزوجات في النفقة والمبيت والمعاملة الظاهرة، فمن خشي على نفسه عدم القدرة على ذلك، أُمر بالاقتصار على واحدة، وهو ما عبَّرت عنه الآية بقولها "ذلك أدنى ألا تعولوا" أي أقرب لعدم الجور والميل.',
   1.0, 14.29, 2, 'published', true),
  (v_unit_id, 'lesson', 'المحرمات من النساء تأبيداً',
   'حرَّم الله تعالى على الرجل نكاح أصناف من النساء تحريماً مؤبَّداً لا يزول بحال، لقرابة نسب أو رضاع أو مصاهرة. قال الله تعالى: ﴿حُرِّمَتْ عَلَيْكُمْ أُمَّهَاتُكُمْ وَبَنَاتُكُمْ وَأَخَوَاتُكُمْ وَعَمَّاتُكُمْ وَخَالَاتُكُمْ وَبَنَاتُ الْأَخِ وَبَنَاتُ الْأُخْتِ وَأُمَّهَاتُكُمُ اللَّاتِي أَرْضَعْنَكُمْ وَأَخَوَاتُكُم مِّنَ الرَّضَاعَةِ وَأُمَّهَاتُ نِسَائِكُمْ وَرَبَائِبُكُمُ اللَّاتِي فِي حُجُورِكُم مِّن نِّسَائِكُمُ اللَّاتِي دَخَلْتُم بِهِنَّ فَإِن لَّمْ تَكُونُوا دَخَلْتُم بِهِنَّ فَلَا جُنَاحَ عَلَيْكُمْ وَحَلَائِلُ أَبْنَائِكُمُ الَّذِينَ مِنْ أَصْلَابِكُمْ وَأَن تَجْمَعُوا بَيْنَ الْأُخْتَيْنِ إِلَّا مَا قَدْ سَلَفَ﴾ (النساء: 23). جمعت الآية سبعة أصناف بالنسب (الأمهات، البنات، الأخوات، العمات، الخالات، بنات الأخ، بنات الأخت)، واثنين بالرضاع (يُقاس عليهما نظائرهما بحديث «يحرم من الرضاعة ما يحرم من النسب»)، وأربعة بالمصاهرة (أم الزوجة، الربيبة بشرط الدخول بأمها، زوجة الابن، والجمع بين الأختين).',
   1.0, 14.29, 3, 'published', true),
  (v_unit_id, 'lesson', 'الطلاق: عدده وأحكامه',
   'الطلاق: حل عقد النكاح بلفظ مخصوص، وهو مباح عند الحاجة مكروه عند عدمها. قال الله تعالى مبيناً عدد الطلاق الذي يملك الزوج فيه الرجعة: ﴿الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ﴾ (البقرة: 229). دلَّت الآية على أن الطلاق الذي يملك فيه الزوج المراجعة مرتان فقط (الأولى والثانية)، فبعدهما يكون الزوج مخيَّراً بين إمساك زوجته بمعروف (أي مراجعتها بنية حسن العشرة) أو تسريحها بإحسان (أي إتمام الفراق دون مضارَّة أو مماطلة)، أما الطلقة الثالثة فتُحرِّم المرأة على زوجها حتى تنكح زوجاً غيره نكاحاً صحيحاً لا تحليلاً.',
   1.0, 14.29, 4, 'published', true),
  (v_unit_id, 'lesson', 'الطلاق الرجعي والبائن',
   'يُقسَّم الطلاق من حيث أثره على قيام الزوجية إلى قسمين رئيسيين: الطلاق الرجعي، وهو الطلقة الأولى أو الثانية إذا كانت المرأة مدخولاً بها، ويملك فيه الزوج مراجعة زوجته خلال عدتها دون عقد جديد ولا مهر؛ والطلاق البائن، وينقسم بدوره إلى بائن بينونة صغرى (كطلاق غير المدخول بها، أو انتهاء عدة الرجعية دون مراجعة) لا تحتاج فيه المرأة لمحلِّل بل يجوز تجديد العقد بمهر ورضا جديدين، وبائن بينونة كبرى (وهي الطلقة الثالثة) لا تحل فيها المرأة لزوجها إلا بعد زواجها من آخر زواجاً صحيحاً مقصوداً لذاته ثم فراقه لها. هذا التدرج في أحكام الطلاق يحفظ للزوجين فرصاً متكررة للمراجعة قبل أن يصبح الفراق نهائياً لا رجعة فيه.',
   1.0, 14.29, 5, 'published', true),
  (v_unit_id, 'lesson', 'الحضانة: أحق الناس بالطفل',
   'الحضانة: حفظ الطفل ورعايته وتربيته لمن لا يستقل بأمر نفسه، وتُعطى الأولوية فيها للأم عند جمهور الفقهاء لكونها أشفق وأرفق بالطفل في سنه الأول. عن عبد الله بن عمرو بن العاص رضي الله عنهما: أن امرأة قالت: يا رسول الله، إن ابني هذا كان بطني له وعاءً، وثديي له سقاءً، وحجري له حواءً، وإن أباه طلقني وأراد أن ينتزعه مني، فقال لها رسول الله ﷺ: «أنتِ أحق به ما لم تنكحي» — رواه أبو داود، كتاب الطلاق (حديث 2276). دلَّ الحديث على أن حق الأم في حضانة ولدها بعد الطلاق مقدَّم على حق الأب ما دامت لم تتزوج بآخر، لأن زواجها قد يشغلها عن حق الطفل أو يُدخل عليه من ليس محرماً له.',
   1.0, 14.29, 6, 'published', true),
  (v_unit_id, 'lesson', 'نفقة الأولاد على الأب',
   'تجب نفقة الأولاد (طعامهم وكسوتهم وسكناهم) على الأب لا على الأم، ولو كانت الأم حاضنة لهم بعد الطلاق. قال الله تعالى في سياق أحكام الرضاعة: ﴿وَالْوَالِدَاتُ يُرْضِعْنَ أَوْلَادَهُنَّ حَوْلَيْنِ كَامِلَيْنِ لِمَنْ أَرَادَ أَن يُتِمَّ الرَّضَاعَةَ وَعَلَى الْمَوْلُودِ لَهُ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ لَا تُكَلَّفُ نَفْسٌ إِلَّا وُسْعَهَا لَا تُضَارَّ وَالِدَةٌ بِوَلَدِهَا وَلَا مَوْلُودٌ لَّهُ بِوَلَدِهِ﴾ (البقرة: 233). عبَّرت الآية عن الأب بـ"المولود له" لا بـ"الزوج" تنبيهاً على أن سبب وجوب النفقة عليه هو البنوة (كونه أباً للولد) لا الزوجية، فتستمر هذه النفقة قائمة حتى بعد الطلاق ما دام الولد يحتاجها، ونهت الآية عن مضارَّة أي من الوالدين بالولد اتخاذاً له وسيلة ضغط على الآخر.',
   1.0, 14.26, 7, 'published', true);

  UPDATE learning_paths lp SET total_sessions = (
    SELECT sum(li.session_estimate)::int
    FROM path_stages ps JOIN courses c ON c.stage_id = ps.id
    JOIN course_units cu ON cu.course_id = c.id
    JOIN learning_items li ON li.unit_id = cu.id
    WHERE ps.path_id = lp.id
  ), updated_at = now() WHERE lp.slug = 'fiqh';
END $$;
